#!/usr/bin/env node
/**
 * Bundle size budget check (Phase 1.250.16).
 *
 * Reads the esbuild metafile (generated by build:web:meta script) and
 * fails if modern_webclient.js exceeds BUDGET_BYTES.
 *
 * Usage:
 *   npm run check:bundle-budget
 *
 * The metafile is produced by:
 *   npm run build:web:meta
 * which runs esbuild with --metafile=addons/web/static/dist/meta.json
 */

"use strict";

const fs = require("fs");
const path = require("path");

const BUDGET_KB = 400;
const BUDGET_BYTES = BUDGET_KB * 1024;
const BUNDLE_NAME = "modern_webclient.js";

const METAFILE_PATH = path.resolve(
  __dirname,
  "../addons/web/static/dist/meta.json"
);
const BUNDLE_PATH = path.resolve(
  __dirname,
  "../addons/web/static/dist/" + BUNDLE_NAME
);

function bytesToKb(n) {
  return (n / 1024).toFixed(1);
}

// ── Try metafile first ────────────────────────────────────────────────────────
let bundleSizeBytes = null;

if (fs.existsSync(METAFILE_PATH)) {
  try {
    const meta = JSON.parse(fs.readFileSync(METAFILE_PATH, "utf8"));
    const outputs = meta.outputs || {};
    for (const [outPath, outInfo] of Object.entries(outputs)) {
      if (outPath.endsWith(BUNDLE_NAME)) {
        bundleSizeBytes = outInfo.bytes;
        break;
      }
    }
    if (bundleSizeBytes === null) {
      console.warn("[budget] " + BUNDLE_NAME + " not found in metafile outputs. Falling back to fs.stat.");
    }
  } catch (e) {
    console.warn("[budget] Failed to read metafile: " + e.message + ". Falling back to fs.stat.");
  }
}

// ── Fallback: direct stat ─────────────────────────────────────────────────────
if (bundleSizeBytes === null) {
  if (!fs.existsSync(BUNDLE_PATH)) {
    console.error("[budget] Bundle not found: " + BUNDLE_PATH);
    console.error("[budget] Run `npm run build:web` first.");
    process.exit(1);
  }
  bundleSizeBytes = fs.statSync(BUNDLE_PATH).size;
}

// ── Report ────────────────────────────────────────────────────────────────────
const kbSize = bytesToKb(bundleSizeBytes);
const headroom = bytesToKb(BUDGET_BYTES - bundleSizeBytes);
const overBudget = bundleSizeBytes > BUDGET_BYTES;

console.log("┌─────────────────────────────────────────");
console.log("│ Bundle size budget check");
console.log("│ File:    " + BUNDLE_NAME);
console.log("│ Size:    " + kbSize + " KB");
console.log("│ Budget:  " + BUDGET_KB + " KB");
if (overBudget) {
  console.log("│ Status:  ❌ OVER BUDGET by " + bytesToKb(bundleSizeBytes - BUDGET_BYTES) + " KB");
} else {
  console.log("│ Status:  ✅ OK (headroom: " + headroom + " KB)");
}
console.log("└─────────────────────────────────────────");

if (overBudget) {
  process.exit(1);
}
